// Solution
int Solution::lengthOfLIS(vector<int> &arr) {
  int n = arr.size();
  int dp[n];
  for (int i = 0; i < n; i++) {
    dp[i] = 1;
  }
  for (int i = 1; i < n; i++) {
    for (int j = 0; j < i; j++) {
      if (arr[i] > arr[j]) {
        dp[i] = dp[i] + 1;
      }
    }
  }
  int max = 0;
  for (int i = 0; i < n; i++) {
    if (dp[i] > max) {
      max = dp[i];
    }
  }
  return max;
}

