// Solution
class Solution: 
def lengthOfLIS(self, arr: list[int]) -> int: 
  n = len(arr) 
  dp = [1] * n 
  for i in range(1, n): 
    for j in range(i): 
      if arr[i] > arr[j]: 
        dp[i] = dp[i] + 1 

  max = 0 
  for i in range(n): 
    if dp[i] > max: 
      max = dp[i] 
  return max

